"""Multiple-comparisons corrections — raise the bar for how many variants you tried.

If you tried N prompt/model/temperature variants and reported the best, the bar must rise.
Bonferroni and Sidak adjust a single reported p-value given the declared N. Benjamini-Hochberg
controls the false-discovery rate when you submit the *whole* set of p-values.
"""
from __future__ import annotations


def bonferroni(p: float, variants_tried: int) -> float:
    """Bonferroni-adjust a p-value for the number of variants tried (no independence needed)."""
    m = max(1, int(variants_tried))
    return min(1.0, p * m)


def sidak(p: float, variants_tried: int) -> float:
    """Sidak adjustment (assumes independence): 1-(1-p)^m. Slightly less conservative."""
    m = max(1, int(variants_tried))
    return 1.0 - (1.0 - p) ** m


def benjamini_hochberg(pvals, alpha: float = 0.05):
    """Benjamini-Hochberg FDR. Returns a list[bool] of rejections aligned to the input order.

    Use this when you ran m variants and want to keep the genuine winners while controlling
    the expected proportion of false discoveries — more powerful than FWER for large m.
    """
    indexed = sorted(enumerate(pvals), key=lambda kv: kv[1])
    m = len(pvals)
    reject = [False] * m
    max_k = -1
    for rank, (orig_i, p) in enumerate(indexed, start=1):
        if p <= (rank / m) * alpha:
            max_k = rank
    if max_k > 0:
        for rank, (orig_i, p) in enumerate(indexed, start=1):
            if rank <= max_k:
                reject[orig_i] = True
    return reject
